body:
### Operating System

Win10 21H2

### x64dbg Version

May 27 2026,12:09:19

### Describe the issue

After calling the `syscall` for `ZwAllocateVirtualMemory`, the size of the following heap page increases from B000 to C000, but when running the following code, the result is still B000
```
Address=00000000004C0000
Size=000000000000C000
Section=User Module
Page Information=Heap (ID 0)
Allocation Type=PRV
Current Protection=-RW--
Initial Protection=-RW--
```

```c++
bool cb_test_PageQuery(int argc, char *argv[]) {
    if (argc < 2) {
        LOG("usage: _test_PageQuery 0x00000000")
        return false;
    }
    const auto addr = std::stoll(argv[1], nullptr, 16);

    MEMORY_BASIC_INFORMATION mbi;

    if (!VirtualQueryEx(DbgGetProcessHandle(), reinterpret_cast<LPCVOID>(addr), &mbi, sizeof(mbi))) {
        LOG("VirtualQueryEx at %s failed with err %lu", argv[1], GetLastError());
        return false;
    }

    LOG("%s", std::format("VirtualQueryEx addr: 0x{:016x}"
                          " AllocationBase: 0x{:016x}"
                          " BaseAddress: 0x{:016x}"
                          " RegionSize: 0x{:016x}"
                          " Protect: 0x{:08x}"
                          " State: 0x{:08x}",
                  (size_t)addr,
                  (size_t)mbi.AllocationBase,
                  (size_t)mbi.BaseAddress,
                  (size_t)mbi.RegionSize,
                  mbi.Protect,
                  mbi.State)
                  .c_str())

    size_t size = 0;
    auto   base = DbgMemFindBaseAddr(addr, &size);
    if (base == 0) {
        LOG("DbgMemFindBaseAddr failed");
        return false;
    }
    LOG("DbgMemFindBaseAddr addr: 0x%016llx, base = 0x%016llx, size = 0x%016llx", addr, base, size);
    return true;
}

bool cb_test_StepInAndQueryPage(int argc, char *argv[]) {
    DbgCmdExecDirect("sti");
    _plugin_waituntilpaused();

    for (int i = 0; i < 5; ++i) {
        cb_test_PageQuery(argc, argv);
        sleep(1);
    }
}
```


I got the following output

```
[CmakeVMHelp] VirtualQueryEx addr: 0x00000000004c0000 AllocationBase: 0x00000000004c0000 BaseAddress: 0x00000000004c0000 RegionSize: 0x000000000000c000 Protect: 0x00000004 State: 0x00001000
[CmakeVMHelp] DbgMemFindBaseAddr addr: 0x00000000004c0000, base = 0x00000000004c0000, size = 0x000000000000b000
[CmakeVMHelp] VirtualQueryEx addr: 0x00000000004c0000 AllocationBase: 0x00000000004c0000 BaseAddress: 0x00000000004c0000 RegionSize: 0x000000000000c000 Protect: 0x00000004 State: 0x00001000
[CmakeVMHelp] DbgMemFindBaseAddr addr: 0x00000000004c0000, base = 0x00000000004c0000, size = 0x000000000000c000
```

### Steps to reproduce

1. Set CIP to the following syscall `00007FFF4D2CD2E2`

<img width="1218" height="98" alt="Image" src="https://github.com/user-attachments/assets/358f2e74-163d-470d-9427-de8bffeb65f8" />

2. run `cb_test_StepInAndQueryPage`



